module top_module(
  input clk_in,
  input reset,
  input [7:0] divider,
  output reg clk_out
);reg [7:0] cnt = 0;

  always @(posedge clk_in or posedge reset) begin
    if (reset) begin
      clk_out <= 0;
      cnt <= 0;
    end else begin
      cnt <= cnt + 1;
      if (cnt == divider) begin
        clk_out <= ~clk_out;
        cnt <= 0;
      end
    end
  end

endmodule
